import React, { useState } from 'react';
import axios from 'axios';
import '../styles/JobForm.css';

function JobForm({ onJobCreated }) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    requiredSkills: '',
    experienceMin: 0,
    experienceMax: 10,
    location: '',
    company: ''
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage({ type: '', text: '' });

    try {
      const skillsArray = formData.requiredSkills
        .split(',')
        .map(skill => skill.trim())
        .filter(skill => skill);

      const jobData = {
        title: formData.title,
        description: formData.description,
        requiredSkills: skillsArray,
        experience: {
          min: parseInt(formData.experienceMin),
          max: parseInt(formData.experienceMax)
        },
        location: formData.location,
        company: formData.company
      };

      const response = await axios.post('http://localhost:5000/api/jobs', jobData);

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Job posted successfully!' });
        setFormData({
          title: '',
          description: '',
          requiredSkills: '',
          experienceMin: 0,
          experienceMax: 10,
          location: '',
          company: ''
        });
        if (onJobCreated) onJobCreated();
      }
    } catch (error) {
      setMessage({ 
        type: 'error', 
        text: error.response?.data?.message || 'Error posting job' 
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="job-form-container">
      <h2>Post a New Job</h2>
      
      {message.text && (
        <div className={`message ${message.type}`}>
          {message.text}
        </div>
      )}

      <form onSubmit={handleSubmit} className="job-form">
        <div className="form-group">
          <label htmlFor="title">Job Title *</label>
          <input
            type="text"
            id="title"
            name="title"
            value={formData.title}
            onChange={handleChange}
            required
            placeholder="e.g., MERN Stack Developer"
          />
        </div>

        <div className="form-group">
          <label htmlFor="company">Company Name</label>
          <input
            type="text"
            id="company"
            name="company"
            value={formData.company}
            onChange={handleChange}
            placeholder="e.g., Tech Corp"
          />
        </div>

        <div className="form-group">
          <label htmlFor="location">Location</label>
          <input
            type="text"
            id="location"
            name="location"
            value={formData.location}
            onChange={handleChange}
            placeholder="e.g., Remote, New York, etc."
          />
        </div>

        <div className="form-group">
          <label htmlFor="description">Job Description *</label>
          <textarea
            id="description"
            name="description"
            value={formData.description}
            onChange={handleChange}
            required
            rows="6"
            placeholder="Describe the job role, responsibilities, and requirements..."
          />
        </div>

        <div className="form-group">
          <label htmlFor="requiredSkills">Required Skills (comma-separated)</label>
          <input
            type="text"
            id="requiredSkills"
            name="requiredSkills"
            value={formData.requiredSkills}
            onChange={handleChange}
            placeholder="e.g., React, Node.js, MongoDB, Machine Learning"
          />
        </div>

        <div className="form-row">
          <div className="form-group">
            <label htmlFor="experienceMin">Min Experience (years)</label>
            <input
              type="number"
              id="experienceMin"
              name="experienceMin"
              value={formData.experienceMin}
              onChange={handleChange}
              min="0"
              max="50"
            />
          </div>

          <div className="form-group">
            <label htmlFor="experienceMax">Max Experience (years)</label>
            <input
              type="number"
              id="experienceMax"
              name="experienceMax"
              value={formData.experienceMax}
              onChange={handleChange}
              min="0"
              max="50"
            />
          </div>
        </div>

        <button type="submit" className="submit-btn" disabled={loading}>
          {loading ? '⏳ Posting...' : '📝 Post Job'}
        </button>
      </form>
    </div>
  );
}

export default JobForm;
